func main() {
	http.HandleFunc("/upload", uploadHandler)
	if err := http.ListenAndServe(":80", nil); err != nil {
		log.Fatalln(err)
	}
}


func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if !isMultipart(r.Header) || r.Method == "GET" {
		renderTemplate(w, "upload")
		return
	}

	if err := parseFormFile(); err != nil {
		return renderError(err)
	}

	f, header, err = parseFormFile()
	if err != nil {
		log.Printf("error in processing upload: %s", err)
		w.WriteHeader(http.StatusInternalServerError)
		io.WriteString(w, "Upload Failed.")
		return
	}
	defer f.Close()

	// Create a buffer to keep file data.
	buf := new(bytes.Buffer)
	if _, err = buf.ReadFrom(f); err != nil {
		log.Printf("error in reading uploaded file: %s", err)
		return renderError(err)
	}

	path, err := saveUploadedFile()
	if err != nil {
		fmt.Println("error in saving uploaded file")
		w.WriteHeader(http.StatusInternalServerError)
		io.WriteString(w, "Upload Failed.")
		log.Println(err)
		return
	}

	io.WriteString(w, fmt.Sprintf("<html><body>Uploaded<br><pre>%s</pre>", path))
}

type Error struct {
	Reason string `json:"reason"`
}

func (e *Error) String() string { return e.Reason }

const (
	uploadError = "Could not parse uploaded file as an image."

	saveErr = "failed to save uploaded image"
)

func saveUploadedFile() (*ebiten.Image, error) {
		// Save image at the location
		ebiten.SavePNG(path + header.Filename + ".png", image)

		return &ebiten.Image{
			Source:      image,
			DisplaySize: size,
		}, nil
}

func parseFormFile() (io.ReadCloser, *multipart.FileHeader, error) {

	// Parse multipart form with a 16MB memory limit.
	err := r.ParseMultipartForm(32 << 20)
	if err != nil {
		log.Printf("error in parsing form file: %s", err)
		return nil, nil, &Error{Reason: uploadError}
	}

	// Grab the first uploaded image from the multipart request.
	if len(r.MultipartForm.File["image"]) == 0 {
		log.Println("couldn't find image in multipart form.")
		return nil, nil, &Error{Reason: uploadError}
	}

	file, header, err := r.FormFile("image")
	if err != nil {
		fmt.Println(err)
		w.WriteHeader(http.StatusInternalServerError)
		io.WriteString(w, "Upload Failed.")
		return file.(image), nil, &Error{Reason: uploadError}

	} else if header == nil || header.Size < 0 || header.Size > maxImageBytes {
		log.Println("upload too large")
		return nil, nil, &Error{Reason: "upload too large"}
	}

	return file.(image), nil, err
}

func isMultipart(header http.Header) bool { return len(r.PostForm) == 0 && header["Content-Type"][0] != `multipart/form-data` }